#' Monte Carlo log-likelihood via importance sampling with augmented trees
#'
#' Augments an observed tree (represented by its branching times) with
#' stochastically drawn extinct lineages, computes importance-sampling
#' weights, and returns a Monte Carlo estimate of the log-likelihood.
#'
#' @param brts Numeric vector of branching times (crown age first,
#'   sorted decreasing).
#' @param pars Numeric vector of model parameters.
#' @param sample_size Number of valid augmented trees to collect.
#' @param maxN Maximum total augmentation attempts (including failures).
#' @param max_missing Maximum number of extinct lineages per tree.
#' @param max_lambda Upper bound on the speciation rate (thinning bound).
#' @param lower_bound Lower bounds for parameter optimisation (same length
#'   as \code{pars}).
#' @param upper_bound Upper bounds for parameter optimisation.
#' @param xtol_rel Relative tolerance for internal optimisation.
#' @param num_threads Number of threads for parallel augmentation.
#' @return A named list:
#' \describe{
#'   \item{trees}{List of augmented-tree data frames (brts, n, t_ext, pd,
#'     id, parent_id).}
#'   \item{weights}{Numeric vector of log importance weights
#'     (\code{logf - logg}).}
#'   \item{fhat}{Monte Carlo log-likelihood estimate.}
#'   \item{logf}{Per-tree log-likelihood values.}
#'   \item{logg}{Per-tree log sampling probabilities.}
#'   \item{rejected}{Number of trees rejected (unhandled).}
#'   \item{rejected_overruns}{Rejected due to too many missing lineages.}
#'   \item{rejected_lambda}{Rejected due to lambda bound exceeded.}
#'   \item{rejected_zero_weights}{Rejected due to zero weight.}
#'   \item{time}{Elapsed time in milliseconds.}
#' }
#' @export
mc_loglik <- function(brts, pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads) {
    .Call('_emphasis_rcpp_mce', PACKAGE = 'emphasis', brts, pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads)
}

#' function to perform one step of the E-M algorithm
#' @param brts vector of branching times
#' @param init_pars vector of initial parameter files
#' @param sample_size number of samples
#' @param maxN maximum number of failed trees
#' @param max_missing maximum number of species missing
#' @param max_lambda maximum speciation rate
#' @param lower_bound vector of lower bound values for optimization, should
#' be equal in length to the vector of init_pars
#' @param upper_bound vector of upper bound values for optimization, should
#' be equal in length to the vector of init_pars
#' @param xtol_rel relative tolerance for optimization
#' @param num_threads number of threads used.
#' @param copy_trees if set to true, the trees generated are returned as well
#' @param rconditional R function that evaluates the GAM function.
#' @return a list with the following components: 
#' \itemize{
#'  \item{trees}{list of trees}
#'  \item{rejected}{number of rejected trees}
#'  \item{rejected_overruns}{number of trees rejected due to too large size}
#'  \item{rejected_lambda}{number of trees rejected due to lambda errors}
#'  \item{rejected_zero_weights}{number of trees rejected to zero weight}
#'  \item{estimates}{vector of estimates}
#'  \item{nlopt}{nlopt status}
#'  \item{fhat}{vector of fhat values}
#'  \item{time}{time elapsed}
#'  \item{weights}{vector of weights}
#' }
#' @export
em_cpp <- function(brts, init_pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads, copy_trees, rconditional = NULL) {
    .Call('_emphasis_rcpp_mcem', PACKAGE = 'emphasis', brts, init_pars, sample_size, maxN, max_missing, max_lambda, lower_bound, upper_bound, xtol_rel, num_threads, copy_trees, rconditional)
}

